package org.apache.commons.math.geometry.euclidean.threed;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.math.geometry.euclidean.threed.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math.geometry.euclidean.threed.steps;

import io.cucumber.java.en.*;
import org.apache.commons.math.geometry.euclidean.threed.Rotation;
import org.apache.commons.math.geometry.euclidean.threed.Vector3D;
import static org.junit.Assert.*;

public class StepDefs {
    private Vector3D u1, u2, v1, v2;
    private Rotation rotation;
    private Exception exception;

    @Given("vector u1 with x={double}, y={double}, z={double}")
    public void vector_u1_with_coordinates(double x, double y, double z) {
        u1 = new Vector3D(x, y, z);
    }

    @Given("vector u2 with x={double}, y={double}, z={double}")
    public void vector_u2_with_coordinates(double x, double y, double z) {
        u2 = new Vector3D(x, y, z);
    }

    @Given("vector v1 as \\({int}, {int}, {int})")
    public void vector_v1_as(int x, int y, int z) {
        v1 = new Vector3D(x, y, z);
    }

    @Given("vector v2 as \\({int}, {int}, {int})")
    public void vector_v2_as(int x, int y, int z) {
        v2 = new Vector3D(x, y, z);
    }

    @When("a Rotation is constructed from u1, u2, v1, v2")
    public void a_rotation_is_constructed_from_u1_u2_v1_v2() {
        try {
            rotation = new Rotation(u1, u2, v1, v2);
            exception = null;
        } catch (Exception e) {
            exception = e;
        }
    }

    @Then("the rotation scalar component q0 should be approximately {double}")
    public void the_rotation_scalar_component_q0_should_be_approximately(double expected) {
        assertNotNull("Rotation should not be null", rotation);
        assertEquals("q0 should match expected value", expected, rotation.getQ0(), 1.0e-15);
    }

    @And("the rotation vector component q1 should be approximately {double}")
    public void the_rotation_vector_component_q1_should_be_approximately(double expected) {
        assertNotNull("Rotation should not be null", rotation);
        assertEquals("q1 should match expected value", expected, rotation.getQ1(), 1.0e-15);
    }

    @And("the rotation vector component q2 should be approximately {double}")
    public void the_rotation_vector_component_q2_should_be_approximately(double expected) {
        assertNotNull("Rotation should not be null", rotation);
        assertEquals("q2 should match expected value", expected, rotation.getQ2(), 1.0e-15);
    }

    @And("the rotation vector component q3 should be approximately {double}")
    public void the_rotation_vector_component_q3_should_be_approximately(double expected) {
        assertNotNull("Rotation should not be null", rotation);
        assertEquals("q3 should match expected value", expected, rotation.getQ3(), 1.0e-15);
    }
}

